import{_ as a,o,c as l,ag as i}from"./chunks/framework.D2Ob5GRY.js";const u=JSON.parse('{"title":"网络与代理配置","description":"","frontmatter":{},"headers":[],"relativePath":"deployment/proxy-config.md","filePath":"deployment/proxy-config.md"}'),t={name:"deployment/proxy-config.md"};function r(n,e,d,c,h,s){return o(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="网络与代理配置" tabindex="-1">网络与代理配置 <a class="header-anchor" href="#网络与代理配置" aria-label="Permalink to &quot;网络与代理配置&quot;">​</a></h1><blockquote><p>国内服务器访问海外 API 的常见问题与代理配置、验证方法。</p></blockquote><h2 id="国内服务器访问海外-api-的常见问题" tabindex="-1">国内服务器访问海外 API 的常见问题 <a class="header-anchor" href="#国内服务器访问海外-api-的常见问题" aria-label="Permalink to &quot;国内服务器访问海外 API 的常见问题&quot;">​</a></h2><ul><li>OpenAI、Gemini 等域名在国内可能无法直连，表现为连接超时或 DNS 解析失败。</li><li>解决方式：在部署环境配置 HTTP/HTTPS 代理，或使用国内可直连的 Provider（如 DeepSeek、通义）。</li></ul><h2 id="配置-https-代理" tabindex="-1">配置 HTTPS 代理 <a class="header-anchor" href="#配置-https-代理" aria-label="Permalink to &quot;配置 HTTPS 代理&quot;">​</a></h2><p>在系统设置「代理配置」中填写：</p><ul><li><code>PROXY_URL</code> 或 <code>HTTPS_PROXY</code>：例如 <code>http://127.0.0.1:7890</code>（与本地代理软件端口一致）。</li><li>若需区分 HTTP/HTTPS，可同时设置 <code>HTTP_PROXY</code> 与 <code>HTTPS_PROXY</code>。</li></ul><p>保存后，后端请求 LLM API 时会通过该代理发出。</p><h2 id="验证代理是否生效" tabindex="-1">验证代理是否生效 <a class="header-anchor" href="#验证代理是否生效" aria-label="Permalink to &quot;验证代理是否生效&quot;">​</a></h2><ul><li>保存代理配置后，在「论文写作」或「文献管理」中发起一次需调用 OpenAI/Gemini 的操作；若此前超时而配置后能正常返回，则代理生效。</li><li>若仍失败，请检查代理软件是否允许局域网或本机连接、防火墙是否放行。</li></ul><h2 id="连接超时的处理方式" tabindex="-1">连接超时的处理方式 <a class="header-anchor" href="#连接超时的处理方式" aria-label="Permalink to &quot;连接超时的处理方式&quot;">​</a></h2><ul><li>适当增大后端请求超时时间（若支持配置）。</li><li>检查代理稳定性与带宽；或改用国内 Provider（DeepSeek、通义）避免代理依赖。</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/troubleshooting/common-errors.html#llm-调用失败">常见错误与解决方法</a></li><li><a href="/docs/reference/env-vars.html">环境变量完整参考</a></li></ul>',14)])])}const P=a(t,[["render",r]]);export{u as __pageData,P as default};
